    23→// Alert wraps a model.Alert with additional information relevant
    24→// to internal of the Alertmanager.
    25→// The type is never exposed to external communication and the
    26→// embedded alert has to be sanitized beforehand.
    27→type Alert struct {
    28→	model.Alert
    29→
    30→	// The authoritative timestamp.
    31→	UpdatedAt time.Time
    32→	Timeout   bool
    33→}
    34→
    35→// Merge merges the timespan of two alerts based and overwrites annotations
    36→// based on the authoritative timestamp.  A new alert is returned, the labels
    37→// are assumed to be equal.
    38→func (a *Alert) Merge(o *Alert) *Alert {
    39→	// Let o always be the younger alert.
    40→	if o.UpdatedAt.Before(a.UpdatedAt) {
    41→		return o.Merge(a)
    42→	}
    43→
    44→	res := *o
    45→
    46→	// Always pick the earliest starting time.
    47→	if a.StartsAt.Before(o.StartsAt) {
    48→		res.StartsAt = a.StartsAt
    49→	}
    50→
    51→	if o.Resolved() {
    52→		// The latest explicit resolved timestamp wins if both alerts are effectively resolved.
    53→		if a.Resolved() && a.EndsAt.After(o.EndsAt) {
    54→			res.EndsAt = a.EndsAt
    55→		}
    56→	} else {
    57→		// A non-timeout timestamp always rules if it is the latest.
    58→		if a.EndsAt.After(o.EndsAt) && !a.Timeout {
    59→			res.EndsAt = a.EndsAt
    60→		}
    61→	}
    62→
    63→	return &res
    64→}
    65→
    66→// Validate overrides the same method in model.Alert to allow UTF-8 labels.
    67→// This can be removed once prometheus/common has support for UTF-8.
    68→func (a *Alert) Validate() error {
    69→	if a.StartsAt.IsZero() {
    70→		return fmt.Errorf("start time missing")
    71→	}
    72→	if !a.EndsAt.IsZero() && a.EndsAt.Before(a.StartsAt) {
    73→		return fmt.Errorf("start time must be before end time")
    74→	}
    75→	if len(a.Labels) == 0 {
    76→		return fmt.Errorf("at least one label pair required")
    77→	}
    78→	if err := validateLs(a.Labels); err != nil {
    79→		return fmt.Errorf("invalid label set: %w", err)
    80→	}
    81→	if err := validateLs(a.Annotations); err != nil {
    82→		return fmt.Errorf("invalid annotations: %w", err)
    83→	}
    84→	return nil
    85→}
    86→
    87→// AlertSlice is a sortable slice of Alerts.
    88→type AlertSlice []*Alert
    89→
    90→func (as AlertSlice) Less(i, j int) bool {
    91→	// Look at labels.job, then labels.instance.
    92→	for _, overrideKey := range [...]model.LabelName{"job", "instance"} {
    93→		iVal, iOk := as[i].Labels[overrideKey]
    94→		jVal, jOk := as[j].Labels[overrideKey]
    95→		if !iOk && !jOk {
    96→			continue
    97→		}
    98→		if !iOk {
    99→			return false
   100→		}
   101→		if !jOk {
   102→			return true
   103→		}
   104→		if iVal != jVal {
   105→			return iVal < jVal
   106→		}
   107→	}
   108→	return as[i].Labels.Before(as[j].Labels)
   109→}
   110→func (as AlertSlice) Swap(i, j int) { as[i], as[j] = as[j], as[i] }
   111→func (as AlertSlice) Len() int      { return len(as) }
   112→
   113→// Alerts turns a sequence of internal alerts into a list of
   114→// exposable model.Alert structures.
   115→func Alerts(alerts ...*Alert) model.Alerts {
   116→	res := make(model.Alerts, 0, len(alerts))
   117→	for _, a := range alerts {
   118→		v := a.Alert
   119→		// If the end timestamp is not reached yet, do not expose it.
   120→		if !a.Resolved() {
   121→			v.EndsAt = time.Time{}
   122→		}
   123→		res = append(res, &v)
   124→	}
   125→	return res
   126→}
