   185→// Key returns a key for the route. It does not uniquely identify the route in general.
   186→func (r *Route) Key() string {
   187→	b := strings.Builder{}
   188→
   189→	if r.parent != nil {
   190→		b.WriteString(r.parent.Key())
   191→		b.WriteRune('/')
   192→	}
   193→	b.WriteString(r.Matchers.String())
   194→	return b.String()
   195→}
   196→
   197→// ID returns a unique identifier for the route.
   198→func (r *Route) ID() string {
   199→	b := strings.Builder{}
   200→
   201→	if r.parent != nil {
   202→		b.WriteString(r.parent.ID())
   203→		b.WriteRune('/')
   204→	}
   205→
   206→	b.WriteString(r.Matchers.String())
   207→
   208→	if r.parent != nil {
   209→		for i := range r.parent.Routes {
   210→			if r == r.parent.Routes[i] {
   211→				b.WriteRune('/')
   212→				b.WriteString(strconv.Itoa(i))
   213→				break
   214→			}
   215→		}
   216→	}
